import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { Button, Select, Tag } from "antd";
import {
  ArrowLeft,
  User,
  Phone,
  Mail,
  MessageSquare,
  ShieldCheck,
  Activity,
  ChevronRight,
  Info,
  CheckCircle2,
  Clock,
} from "lucide-react";
import {
  getAEnquiry,
  resetState,
  updateAEnquiry,
} from "../features/enquiry/enquirySlice";

const ViewEnq = () => {
  const location = useLocation();
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const getEnqId = location.pathname.split("/")[3];
  const enqState = useSelector((state) => state.enquiry);
  const { enqName, enqMobile, enqEmail, enqComment, enqStatus } = enqState;

  useEffect(() => {
    dispatch(getAEnquiry(getEnqId));
  }, [getEnqId]);

  const goBack = () => {
    navigate(-1);
  };

  const setEnquiryStatus = (value) => {
    const data = { id: getEnqId, enqData: value };
    dispatch(updateAEnquiry(data));
    dispatch(resetState());
    setTimeout(() => {
      dispatch(getAEnquiry(getEnqId));
    }, 100);
  };

  const statusConfig = {
    Resolved: {
      color: "success",
      icon: <CheckCircle2 size={12} />,
      label: "RESOLVED",
    },
    "In Progress": {
      color: "processing",
      icon: <Activity size={12} />,
      label: "IN PROGRESS",
    },
    Contacted: {
      color: "warning",
      icon: <Phone size={12} />,
      label: "CONTACTED",
    },
    Submitted: {
      color: "default",
      icon: <Clock size={12} />,
      label: "SUBMITTED",
    },
  };

  const currentStatus = statusConfig[enqStatus] || statusConfig.Submitted;

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <div className="flex items-center gap-3">
            <h1 className="text-[28px] font-bold text-black">
              Enquiry Details
            </h1>
            <div className="flex items-center gap-2">
              <Tag
                color={currentStatus.color}
                className="rounded-full px-3 py-0.5 text-[11px] font-bold border-none flex items-center gap-1.5"
              >
                {currentStatus.icon} {currentStatus.label}
              </Tag>
            </div>
          </div>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[14px] text-slate-500 font-medium">
              Enquiry ID:
            </span>
            <span className="font-mono text-[14px] font-bold text-black uppercase tracking-wider">
              #{getEnqId?.slice(-6).toUpperCase()}
            </span>
          </div>
        </div>
        <Button
          onClick={goBack}
          className="h-11 rounded-xl font-bold flex items-center gap-2 border-slate-200 text-slate-600 px-6 hover:bg-slate-50"
        >
          <ArrowLeft size={18} /> Back to List
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          {/* Customer Info */}
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-50 flex items-center gap-3">
              <div className="p-2 bg-blue-50 rounded-lg">
                <User size={20} className="text-blue-600" />
              </div>
              <h3 className="text-[18px] font-bold text-black">
                Customer Information
              </h3>
            </div>
            <div className="p-8">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="space-y-1">
                  <p className="text-[12px] font-bold text-slate-400 uppercase tracking-wider pl-1">
                    Full Name
                  </p>
                  <div className="p-4 rounded-xl bg-slate-50 border border-slate-100 font-bold text-black">
                    {enqName}
                  </div>
                </div>
                <div className="space-y-1">
                  <p className="text-[12px] font-bold text-slate-400 uppercase tracking-wider pl-1">
                    Phone Number
                  </p>
                  <a
                    href={`tel:${enqMobile}`}
                    className="p-4 rounded-xl bg-slate-50 border border-slate-100 font-bold text-black hover:text-blue-600 hover:border-blue-200 transition-all flex items-center gap-2"
                  >
                    <Phone size={14} className="text-blue-500" /> {enqMobile}
                  </a>
                </div>
                <div className="space-y-1">
                  <p className="text-[12px] font-bold text-slate-400 uppercase tracking-wider pl-1">
                    Email Address
                  </p>
                  <a
                    href={`mailto:${enqEmail}`}
                    className="p-4 rounded-xl bg-slate-50 border border-slate-100 font-bold text-black hover:text-blue-600 hover:border-blue-200 transition-all flex items-center gap-2"
                  >
                    <Mail size={14} className="text-blue-500" /> {enqEmail}
                  </a>
                </div>
              </div>
            </div>
          </div>

          {/* Enquiry Message */}
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-50 flex items-center gap-3">
              <div className="p-2 bg-purple-50 rounded-lg">
                <MessageSquare size={20} className="text-purple-600" />
              </div>
              <h3 className="text-[18px] font-bold text-black">
                Enquiry Message
              </h3>
            </div>
            <div className="p-8">
              <div className="p-6 rounded-2xl bg-slate-50/80 border border-slate-100 min-h-[150px]">
                <p className="text-[15px] font-medium text-slate-700 leading-relaxed whitespace-pre-wrap">
                  {enqComment || "No message provided."}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-8">
          {/* Status Control */}
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-8 space-y-6">
            <div className="flex items-center gap-2">
              <Activity size={18} className="text-blue-600" />
              <h3 className="text-[16px] font-bold text-black uppercase tracking-wider">
                Update Status
              </h3>
            </div>
            <div className="space-y-2">
              <Select
                value={enqStatus || "Submitted"}
                onChange={(value) => setEnquiryStatus(value)}
                className="w-full h-12 modern-select"
                bordered={false}
              >
                <Select.Option value="Submitted">Submitted</Select.Option>
                <Select.Option value="Contacted">Contacted</Select.Option>
                <Select.Option value="In Progress">In Progress</Select.Option>
                <Select.Option value="Resolved">Resolved</Select.Option>
              </Select>
            </div>
            <div className="pt-4 border-t border-slate-50 flex items-start gap-3">
              <Info size={16} className="text-slate-400 mt-1" />
              <p className="text-[13px] text-slate-500 font-medium">
                Updating the status helps other team members track the progress
                of this enquiry.
              </p>
            </div>
          </div>

          {/* Support Branding */}
          <div className="bg-[#1e3a8a] rounded-2xl p-8 text-white relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform duration-700">
              <ShieldCheck size={120} />
            </div>
            <div className="relative z-10">
              <h4 className="text-[18px] font-bold mb-2 italic">
                Support Excellence
              </h4>
              <p className="text-[14px] text-blue-100/80 leading-relaxed font-medium">
                Ensure professional and timely responses to all patient and
                customer enquiries.
              </p>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .modern-select .ant-select-selector {
          background: #f8fafc !important;
          border-radius: 12px !important;
          border: 1px solid #e2e8f0 !important;
          padding: 0 12px !important;
          font-weight: 600 !important;
          font-size: 14px !important;
          display: flex !important;
          align-items: center !important;
        }
      `}</style>
    </div>
  );
};

export default ViewEnq;
